'use strict';

/**
 * District Angels — deal/investor matching (conditional rules, no scoring).
 *
 * Runs in two places, unchanged:
 *   1. An n8n Code node — paste this whole file, then the driver snippet at the
 *      bottom of this file (see N8N DRIVER) as the last lines of the node.
 *   2. Plain Node.js for tests: `node --test` from the repo root.
 *
 * Zero dependencies. All values arrive as strings from Google Sheets.
 */

// Config keys the Config tab may override. Values are strings, as in the Sheet.
const DEFAULT_CONFIG = {
  enforce_geography: 'TRUE',
  enforce_founder_type: 'TRUE',
  enforce_raise_band: 'TRUE',
  // JSON object in one Config cell, e.g. {"health tech":"healthtech","ai/ml":"ai"}
  industry_aliases: '{}',
  max_deals_per_digest: '5',
};

// Log statuses that count as "this contact already got this deal".
const ALREADY_SENT_STATUSES = ['sent', 'approved'];

function truthy(value) {
  if (typeof value === 'boolean') return value;
  const s = String(value == null ? '' : value).trim().toLowerCase();
  return s === 'true' || s === 'yes' || s === '1' || s === 'x' || s === 'checked';
}

function toNumber(value) {
  if (value == null || String(value).trim() === '') return null;
  const n = Number(String(value).replace(/[$,\s]/g, ''));
  return Number.isFinite(n) ? n : null;
}

// "FinTech " / "fin-tech" / "fin_tech" all become "fin tech" before aliasing.
function cleanTerm(value) {
  return String(value == null ? '' : value)
    .trim()
    .toLowerCase()
    .replace(/[\s_-]+/g, ' ');
}

function buildConfig(configRows) {
  const config = Object.assign({}, DEFAULT_CONFIG);
  for (const row of configRows || []) {
    const key = cleanTerm(row.key).replace(/ /g, '_');
    if (key) config[key] = row.value == null ? '' : String(row.value);
  }
  return config;
}

function makeNormalizer(config) {
  let raw = {};
  try {
    raw = JSON.parse(config.industry_aliases || '{}');
  } catch (err) {
    raw = {}; // a malformed alias map must never break a send cycle
  }
  const aliases = {};
  for (const key of Object.keys(raw)) aliases[cleanTerm(key)] = cleanTerm(raw[key]);
  return term => {
    const t = cleanTerm(term);
    return aliases[t] || t;
  };
}

function splitList(value, normalize) {
  return String(value == null ? '' : value)
    .split(/[,;\n]/)
    .map(normalize)
    .filter(Boolean);
}

function overlap(listA, listB) {
  const set = new Set(listA);
  return listB.filter(item => set.has(item));
}

/**
 * Contact-level gates (independent of any deal).
 * Returns null when the contact is eligible, otherwise a reason string.
 */
function contactGate(contact, normalize) {
  if (normalize(contact.role_type) !== 'investor') return 'not_investor';
  const email = String(contact.email || '').trim();
  if (!email || !email.includes('@')) return 'no_email';
  if (truthy(contact.do_not_contact)) return 'do_not_contact';
  if (truthy(contact.unsubscribed_deals)) return 'unsubscribed';
  return null;
}

/**
 * Pair-level gates for one (contact, deal).
 * Returns { ok: true, reasons: [...] } with human-readable match reasons,
 * or { ok: false, reason: '<gate name>' }.
 */
function pairGate(contact, deal, config, normalize, alreadySentKeys) {
  const reasons = [];

  if (alreadySentKeys.has(`${deal.deal_id}|${contact.contact_id}`)) {
    return { ok: false, reason: 'already_sent' };
  }

  // Stage: investor's list must contain the deal stage. Blank or "any" = all stages.
  const stages = splitList(contact.investing_stage_pref, normalize);
  const dealStage = normalize(deal.stage);
  if (stages.length && !stages.includes('any')) {
    if (!dealStage || !stages.includes(dealStage)) return { ok: false, reason: 'stage' };
    reasons.push(`stage: ${dealStage}`);
  }

  // Industry: at least one overlap. Blank investor list = generalist, passes.
  const wants = splitList(contact.industries, normalize);
  const has = splitList(deal.industries, normalize);
  if (wants.length && has.length) {
    const common = overlap(wants, has);
    if (!common.length) return { ok: false, reason: 'industry' };
    reasons.push(`industry: ${common.join(', ')}`);
  }

  // Geography: blank on either side = anywhere.
  if (truthy(config.enforce_geography)) {
    const contactGeo = splitList(contact.geography, normalize);
    const dealGeo = splitList(deal.geography, normalize);
    if (contactGeo.length && dealGeo.length) {
      const common = overlap(contactGeo, dealGeo);
      if (!common.length) return { ok: false, reason: 'geography' };
      reasons.push(`geo: ${common.join(', ')}`);
    }
  }

  // Founder type: only enforced when BOTH sides tagged something.
  if (truthy(config.enforce_founder_type)) {
    const interests = splitList(contact.founder_type_interests, normalize);
    const tags = splitList(deal.founder_type_tags, normalize);
    if (interests.length && tags.length) {
      const common = overlap(interests, tags);
      if (!common.length) return { ok: false, reason: 'founder_type' };
      reasons.push(`founder: ${common.join(', ')}`);
    }
  }

  // Raise band: if the investor set a min/max raise they play in, the deal's
  // raise must fall inside it. Missing numbers on either side = no gate.
  if (truthy(config.enforce_raise_band)) {
    const raise = toNumber(deal.raise_amount);
    const min = toNumber(contact.min_check);
    const max = toNumber(contact.max_check);
    if (raise != null) {
      if (min != null && raise < min) return { ok: false, reason: 'raise_band' };
      if (max != null && raise > max) return { ok: false, reason: 'raise_band' };
    }
  }

  return { ok: true, reasons };
}

/**
 * Main entry point.
 * @param {Array<Object>} contacts   rows from the Contacts tab
 * @param {Array<Object>} deals      rows from the Deals tab (all rows OK; flag is re-checked)
 * @param {Array<Object>} logRows    rows from the Distribution_Log tab
 * @param {Array<Object>} configRows rows from the Config tab ({key, value})
 * @returns {{recipients: Array, excluded: Object, summary: Object}}
 */
function matchCycle(contacts, deals, logRows, configRows) {
  const config = buildConfig(configRows);
  const normalize = makeNormalizer(config);
  const maxDeals = toNumber(config.max_deals_per_digest) || 5;

  const flaggedDeals = (deals || []).filter(
    d => truthy(d.include_in_next_send) && String(d.deal_id || '').trim()
  );

  const alreadySentKeys = new Set();
  for (const row of logRows || []) {
    if (ALREADY_SENT_STATUSES.includes(cleanTerm(row.status))) {
      alreadySentKeys.add(`${row.deal_id}|${row.contact_id}`);
    }
  }

  const excluded = {}; // reason -> count (contact-level counts contacts, pair-level counts pairs)
  const bump = reason => {
    excluded[reason] = (excluded[reason] || 0) + 1;
  };

  const recipients = [];
  for (const contact of contacts || []) {
    const contactReason = contactGate(contact, normalize);
    if (contactReason) {
      bump(contactReason);
      continue;
    }

    const matchedDeals = [];
    for (const deal of flaggedDeals) {
      const result = pairGate(contact, deal, config, normalize, alreadySentKeys);
      if (!result.ok) {
        bump(result.reason);
        continue;
      }
      matchedDeals.push({
        deal_id: deal.deal_id,
        company_name: deal.company_name,
        match_reasons: result.reasons.join('; ') || 'generalist match',
      });
    }

    if (!matchedDeals.length) continue;
    if (matchedDeals.length > maxDeals) {
      bump('over_digest_cap');
      matchedDeals.length = maxDeals;
    }

    recipients.push({
      contact_id: contact.contact_id,
      email: String(contact.email).trim(),
      first_name: contact.first_name || '',
      last_name: contact.last_name || '',
      can_help_with: contact.can_help_with || '',
      deals: matchedDeals,
    });
  }

  return {
    recipients,
    excluded,
    summary: {
      flagged_deals: flaggedDeals.length,
      contacts_considered: (contacts || []).length,
      recipients: recipients.length,
      pairs: recipients.reduce((n, r) => n + r.deals.length, 0),
    },
  };
}

/* ---------------------------------------------------------------------------
 * N8N DRIVER — inside the "Match Investors" Code node, keep everything above
 * as-is and finish the node with these lines (uncommented):
 *
 * const contacts   = $('Read Contacts').all().map(i => i.json);
 * const deals      = $('Read Deals').all().map(i => i.json);
 * const logRows    = $('Read Log').all().map(i => i.json);
 * const configRows = $('Read Config').all().map(i => i.json);
 * return [{ json: matchCycle(contacts, deals, logRows, configRows) }];
 * ------------------------------------------------------------------------- */

if (typeof module !== 'undefined' && module.exports) {
  module.exports = {
    matchCycle,
    contactGate,
    pairGate,
    buildConfig,
    makeNormalizer,
    splitList,
    truthy,
    toNumber,
    cleanTerm,
  };
}

// ---- n8n driver (reads the four sheet tabs, runs the matcher) ----
const contacts   = $('Read Contacts').all().map(i => i.json);
const deals      = $('Read Deals').all().map(i => i.json);
const logRows    = $('Read Log').all().map(i => i.json);
const configRows = $('Read Config').all().map(i => i.json);

const result = matchCycle(contacts, deals, logRows, configRows);
const config = buildConfig(configRows);
const cycleId = new Date().toISOString().slice(0, 10) + '-' + Math.random().toString(36).slice(2, 6);

return [{ json: Object.assign({ cycle_id: cycleId, config: config }, result) }];

// Chunk recipients into groups of 4 per LLM call to conserve free-tier quota.
// The canonical prompt lives in prompts/digest_email.md - keep them in sync.
const INSTRUCTION = "You draft deal-digest emails for District Angels, an angel investing community.\nEach email goes from {{sender_name}} to one member investor and covers the deals\nlisted for that investor - nothing else.\n\nVoice: warm, direct, peer-to-peer. 100-180 words total. No hype (\"exciting\nopportunity\", \"rocket ship\", \"game-changing\"), no fabricated facts - use ONLY\nthe deal facts provided. Do not invent traction, metrics, or names.\n\nStructure per email:\n1. Greeting with first name, then ONE personal opener line - use the investor's\n   interests or can_help_with if given; otherwise a simple \"a few deals from\n   this month's pipeline that fit your focus\".\n2. One short block per deal: company name in plain text, the one-liner,\n   stage + raise, our take (from why_compelling), then the deck link on its\n   own line.\n3. Soft close: \"Reply if you'd like an intro or the full memo.\" Nothing pushier.\n4. No signature - it is appended automatically.\n\nSubject line: <= 60 characters, plain, names one or two companies. No emojis,\nno clickbait.\n\nReturn STRICT JSON only - no markdown fences, no commentary - exactly:\n[{\"contact_id\": \"...\", \"subject\": \"...\", \"body\": \"...\"}]\nOne object per investor below, same contact_id values, plain-text body with\nblank lines between blocks.";

const src = $input.first().json;
const dealRows = $('Read Deals').all().map(i => i.json);
const senderName = src.config.sender_name || 'District Angels';
const batches = [];
for (let i = 0; i < src.recipients.length; i += 4) {
  const group = src.recipients.slice(i, i + 4).map(function (r) {
    return {
      contact_id: r.contact_id,
      first_name: r.first_name,
      can_help_with: r.can_help_with,
      deals: r.deals.map(function (d) {
        const deal = dealRows.find(function (x) { return x.deal_id === d.deal_id; }) || {};
        return {
          company_name: deal.company_name,
          one_liner: deal.one_liner,
          stage: deal.stage,
          raise_amount: deal.raise_amount,
          why_compelling: deal.why_compelling,
          deck_url: deal.deck_url,
          match_reasons: d.match_reasons,
        };
      }),
    };
  });
  const prompt = INSTRUCTION.split('{{sender_name}}').join(senderName)
    + '\n\nINVESTORS:\n' + JSON.stringify(group, null, 2);
  batches.push({ json: { prompt: prompt, batch: group } });
}
return batches;

// Collect LLM drafts by contact_id; anyone missing (LLM error, bad JSON,
// rate limit) gets the plain template so a cycle never blocks.
const src = $('Match Investors').first().json;
const batches = $('Build LLM Batches').all().map(i => i.json);

const drafts = {};
for (const item of $input.all()) {
  const j = item.json || {};
  let text = '';
  if (j.candidates && j.candidates[0]) {
    text = (((j.candidates[0].content || {}).parts || [])[0] || {}).text || '';
  } else if (j.choices && j.choices[0]) {
    text = (j.choices[0].message || {}).content || '';
  }
  if (!text) continue; // errored item -> template fallback below
  try {
    const m = String(text).match(/\[[\s\S]*\]/);
    const arr = JSON.parse(m ? m[0] : text);
    for (const d of arr) {
      if (d && d.contact_id && d.subject && d.body) drafts[d.contact_id] = d;
    }
  } catch (e) { /* template fallback below */ }
}

const allBatchEntries = [];
for (const b of batches) for (const e of b.batch) allBatchEntries.push(e);
const month = new Date().toLocaleString('en-US', { month: 'long' });

const out = [];
for (const r of src.recipients) {
  const entry = allBatchEntries.find(function (x) { return x.contact_id === r.contact_id; }) || { deals: [] };
  let d = drafts[r.contact_id];
  if (!d) {
    const names = entry.deals.map(function (x) { return x.company_name; }).join(' + ');
    const blocks = entry.deals.map(function (x) {
      return '- ' + x.company_name + ' - ' + (x.one_liner || '') + '\n  '
        + (x.stage || '') + ', raising ' + (x.raise_amount || 'n/a')
        + (x.why_compelling ? '. Our take: ' + x.why_compelling : '')
        + (x.deck_url ? '\n  Deck: ' + x.deck_url : '');
    }).join('\n\n');
    d = {
      subject: ('District Angels deals - ' + month + ': ' + names).slice(0, 78),
      body: 'Hi ' + (r.first_name || 'there') + ',\n\n'
        + "A few deals from this month's pipeline that matched your focus:\n\n"
        + blocks + '\n\n' + "Reply if you'd like an intro or the full memo.",
    };
  }
  out.push({ json: {
    cycle_id: src.cycle_id,
    contact_id: r.contact_id,
    contact_name: ((r.first_name || '') + ' ' + (r.last_name || '')).trim(),
    email: r.email,
    first_name: r.first_name,
    subject: d.subject,
    body: d.body,
    deals: r.deals,
  } });
}
return out;

// One Distribution_Log row per (deal, investor) pair.
const out = [];
for (const item of $input.all()) {
  const r = item.json;
  for (const d of r.deals) {
    out.push({ json: {
      cycle_id: r.cycle_id,
      deal_id: d.deal_id,
      company_name: d.company_name,
      contact_id: r.contact_id,
      contact_name: r.contact_name,
      email: r.email,
      match_reasons: d.match_reasons,
      include: 'TRUE',
      digest_subject: r.subject,
      digest_body: r.body,
      status: 'SUGGESTED',
      sent_at: '',
      gmail_message_id: '',
    } });
  }
}
return out;

// Human-readable cycle summary for the Slack approval card.
const src = $('Match Investors').first().json;
const drafts = $('Parse Drafts').all().map(i => i.json);
const sample = drafts[0] || { email: '(none)', subject: '(none)', body: '' };
const excluded = Object.keys(src.excluded).map(function (k) { return src.excluded[k] + ' ' + k; }).join(', ') || 'none';

const perDeal = {};
for (const item of $('Build Log Rows').all()) {
  const j = item.json;
  if (!perDeal[j.company_name]) perDeal[j.company_name] = 0;
  perDeal[j.company_name] += 1;
}
const dealLines = Object.keys(perDeal).map(function (name) { return '- ' + name + ': ' + perDeal[name] + ' investor(s)'; }).join('\n');

const fence = String.fromCharCode(96, 96, 96);
const text = [
  '*Deal cycle ' + src.cycle_id + '* - ' + src.summary.flagged_deals + ' deal(s) -> ' + src.summary.recipients + ' investor(s), ' + src.summary.pairs + ' pairing(s).',
  dealLines,
  'Excluded: ' + excluded + '.',
  '',
  '*Sample email (' + sample.email + ')* - subject: ' + sample.subject,
  fence + String(sample.body).slice(0, 1200) + fence,
  '',
  '_Edit drafts or untick include in the Distribution_Log tab BEFORE approving - the send step re-reads the sheet._',
].join('\n');

return [{ json: { text: text, cycle_id: src.cycle_id } }];

// Re-read after approval so human edits in the sheet win.
const cycleId = $('Match Investors').first().json.cycle_id;
const cfgRows = $('Read Config').all().map(i => i.json);
const sig = (cfgRows.find(function (r) { return r.key === 'email_signature'; }) || {}).value || '';

function truthyCell(v) {
  const s = String(v == null ? '' : v).trim().toLowerCase();
  return s === 'true' || s === 'yes' || s === '1' || s === 'x' || s === 'checked';
}

const rows = $input.all().map(i => i.json).filter(function (r) {
  return r.cycle_id === cycleId && String(r.status).trim().toUpperCase() === 'SUGGESTED' && truthyCell(r.include);
});

const byContact = {};
for (const r of rows) {
  if (!byContact[r.contact_id]) {
    byContact[r.contact_id] = {
      contact_id: r.contact_id,
      email: r.email,
      subject: r.digest_subject,
      body: String(r.digest_body || '') + (sig ? '\n\n' + sig : ''),
      row_numbers: [],
    };
  }
  byContact[r.contact_id].row_numbers.push(r.row_number);
}
return Object.keys(byContact).map(function (k) { return { json: byContact[k] }; });

// Flip this recipient's log rows to SENT (keyed by sheet row_number).
const rec = $('One By One').first().json;
const msg = $input.first().json || {};
return rec.row_numbers.map(function (n) {
  return { json: {
    row_number: n,
    status: 'SENT',
    sent_at: new Date().toISOString(),
    gmail_message_id: msg.id || '',
  } };
});

// Clear flags on every deal that was in this cycle; record outcome.
function truthyCell(v) {
  const s = String(v == null ? '' : v).trim().toLowerCase();
  return s === 'true' || s === 'yes' || s === '1' || s === 'x' || s === 'checked';
}
const pairedDeals = {};
for (const item of $('Build Log Rows').all()) pairedDeals[item.json.deal_id] = true;

const rows = $input.all().map(i => i.json).filter(function (r) { return truthyCell(r.include_in_next_send); });
return rows.map(function (r) {
  return { json: {
    row_number: r.row_number,
    include_in_next_send: 'FALSE',
    send_status: pairedDeals[r.deal_id] ? 'SENT' : 'NO_MATCHES',
    last_sent_at: new Date().toISOString(),
  } };
});
